586: const Pseudoword = struct {
587:     // The start position of the word on State.buffer_effective.
588:     start: u8,
589:     // The end position of the word on State.buffer_effective.
590:     end: u8,
591:     // The start position of the vowels on State.buffer_effective.
592:     vowels_start: ?u8,
593:     // The end position of the vowels on State.buffer_effective.
594:     vowels_end: ?u8,
595:     // The length of the word.
596:     length: u8,
