603: const buffer_effective_length: u8 = 16;
604: 
605: const State = struct {
606:     // The effective buffer to process Vietnamese input. we will skip processing if the buffer
607:     // longer than 15. The last input is always literal.
608:     buffer_effective: [buffer_effective_length]Span,
609:     // The maximum buffer length that the engine still keeps the effective buffer, after the maximum
610:     // value (255), we will reset the effective buffer and this value.
611:     buffer_length: u8 = 0,
612:     // The previous buffer length before State.add is called, used to calculate synthetic backspaces.
613:     buffer_length_previous: u8 = 0,
614:     // Mark the earliest position (inclusive) in buffer where we modified the span, will be used to
615:     // calculate backspaces and replacement characters.
616:     buffer_modification_index: ?u8 = null,
617:     // Mark the position (inclusive) in buffer_effective where the engine stops Telex processing
618:     // and appends the remaining composition literally. Positions before literal_index were
619:     // processed as Telex, positions on or after literal_index form the "literal tail". null means
620:     // the whole current buffer_effective remains Telex-processable.
621:     literal_index: ?u8 = null,
622: 
623:     // Initialize the State on allocated memory.
624:     fn init(self: *State) void {
625:         self.* = .{
626:             .buffer_effective = undefined,
627:         };
628:     }
629: 
630:     fn add(self: *State, c: u8) void {
631:         // Only allow a-zA-Z.
632:         assert(isAlphabetic(c));
633: 
634:         if (self.literal_index) |literal_index| {
635:             // The literal_index value must be in range null or 0 -> 15 (within buffer_effective)
636:             // because we won't process Vietnamese input outside the buffer_effective and need the
637:             // literal character for replacement composition.
638:             assert(literal_index < self.buffer_effective.len);
639:             // The literal_index value must be less than buffer length.
640:             assert(literal_index < self.buffer_length);
641:         }
642: 
643:         // buffer_length conditions
644:         // 1. must be within buffer_effective length while the whole buffer is Telex-processable.
645:         // 2. could be equal or more than buffer_effective after literal_index starts the literal
646:         //    tail.
647:         assert(self.buffer_length < self.buffer_effective.len or self.literal_index != null);
648: 
649:         // Reset buffer_modification_index to start the new action.
650:         self.buffer_modification_index = null;
651: 
652:         // Keep the buffer_length in buffer_length_previous for synthetic backspace calculation.
653:         self.buffer_length_previous = self.buffer_length;
654: 
655:         switch (c) {
656:             'A', 'a' => {
657:                 if (self.literal_index != null or self.buffer_length == 0) {
658:                     // 1. Append literally when literal_index is set.
659:                     // 2. Append literal because no previous span existed. Continue Vietnamese
660:                     // processing on next input.
661:                     self.append_literal(c);
662:                     // Set modification index to null because we didn't modify any existing span.
663:                     self.buffer_modification_index = null;
664:                 } else if (self.buffer_effective_last().equals_ignore_case_tone(c, .empty)) {
665:                     // 3. Previous span is 'A' or 'a', apply circumflex.
666:                     const span_previous = self.buffer_effective[self.buffer_length - 1];
667:                     self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .circumflex, span_previous.tone);
668:                     // Set modification index for calculating synthetic backspace.
669:                     self.buffer_modification_index = self.buffer_length - 1;
670:                 } else if (self.buffer_effective_last().equals_ignore_case_tone(c, .breve)) {
671:                     // 4. Previous span is 'Ă' or 'ă', override to circumflex.
672:                     const span_previous = self.buffer_effective[self.buffer_length - 1];
673:                     self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .circumflex, span_previous.tone);
674:                     // Set modification index for calculating synthetic backspace.
675:                     self.buffer_modification_index = self.buffer_length - 1;
676:                 } else if (self.buffer_effective_last().equals_ignore_case_tone(c, .circumflex)) {
677:                     // 5. Previous span is 'Â' or 'â', cancel circumflex for previous span and append new literal span.
678:                     const span_previous = self.buffer_effective[self.buffer_length - 1];
679:                     self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .empty, span_previous.tone);
680:                     // Set modification index for calculating synthetic backspace.
681:                     self.buffer_modification_index = self.buffer_length - 1;
682:                     // Start literal input from this position.
683:                     self.literal_index = self.buffer_length;
684:                     // Append literal 'A' or 'a'.
685:                     self.append_literal(c);
686:                 } else if (!self.buffer_effective_last().equals_ignore_case_diacritic_tone(c)) {
687:                     // 6. Append literal when previous span is not 'A', 'a' and its variants.
688:                     self.append_literal(c);
